import{_ as a,o,c as n,a2 as t}from"./chunks/framework.CHeM0PsO.js";const p=JSON.parse('{"title":"ADR-0005: Sovereign Console Namespace and Health Boundary","description":"","frontmatter":{},"headers":[],"relativePath":"sovereign-os/adrs/0005-sovereign-console-and-health-boundary.md","filePath":"sovereign-os/adrs/0005-sovereign-console-and-health-boundary.md"}'),i={name:"sovereign-os/adrs/0005-sovereign-console-and-health-boundary.md"};function r(s,e,d,l,c,h){return o(),n("div",null,[...e[0]||(e[0]=[t('<h1 id="adr-0005-sovereign-console-namespace-and-health-boundary" tabindex="-1">ADR-0005: Sovereign Console Namespace and Health Boundary <a class="header-anchor" href="#adr-0005-sovereign-console-namespace-and-health-boundary" aria-label="Permalink to &quot;ADR-0005: Sovereign Console Namespace and Health Boundary&quot;">​</a></h1><p><strong>Status:</strong> Accepted</p><p><strong>Date:</strong> 2026-07-22</p><p><strong>Decision owner:</strong> Project creator</p><p><strong>Related plan:</strong> <a href="./../roadmap/01-console-foundation.html">Console Foundation</a></p><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>The appliance currently sends <code>/</code> directly to Pi-hole. That proves the first service but presents Sovereign OS as a Pi-hole image rather than a platform. Upcoming updates, model management, search, conversation, and home automation need one coherent product entry point without absorbing the independent service namespaces.</p><p>The first interface only needs read-only health. It must remain useful when Pi-hole is degraded and must not require broad root, systemd, or Docker access.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><ul><li>The product is named <strong>Sovereign Console</strong>.</li><li><code>/console/</code> is the canonical human interface namespace.</li><li><code>/</code> redirects to <code>/console/</code>.</li><li><code>/console/health/</code> is the stable detailed health page; the initial Console overview may render the same experience.</li><li><code>/api/v1/health</code> is the machine-readable Sovereign health resource.</li><li>Existing services keep independent namespaces such as <code>/dns/*</code>.</li><li>The initial Console is read-only and available on the trusted LAN under the preview security model.</li><li>A dedicated unprivileged loopback service produces bounded health data.</li><li>Nginx remains the only LAN-facing HTTP service.</li><li>The Console does not receive the Docker socket, service credentials, raw DNS history, unrestricted logs, or mutating operations.</li><li>Authentication is required before settings, restarts, updates, credential changes, detailed logs, or other state-changing operations are added.</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><h3 id="positive" tabindex="-1">Positive <a class="header-anchor" href="#positive" aria-label="Permalink to &quot;Positive&quot;">​</a></h3><ul><li>Sovereign gains a durable product entry point independent of Pi-hole.</li><li>Updates, diagnostics, the assistant, and future services can reuse one health vocabulary and API.</li><li>Third-party applications remain modular and directly addressable.</li><li>The first implementation can remain small and privilege-minimized.</li></ul><h3 id="negative" tabindex="-1">Negative <a class="header-anchor" href="#negative" aria-label="Permalink to &quot;Negative&quot;">​</a></h3><ul><li>Sovereign now owns and must maintain a web interface and health API.</li><li>LAN-visible health data requires an explicit minimal-disclosure policy.</li><li>Root routing changes, so documentation and physical qualification must verify the new entry point.</li></ul><h2 id="rejected-alternatives" tabindex="-1">Rejected Alternatives <a class="header-anchor" href="#rejected-alternatives" aria-label="Permalink to &quot;Rejected Alternatives&quot;">​</a></h2><h3 id="control" tabindex="-1"><code>/control/</code> <a class="header-anchor" href="#control" aria-label="Permalink to &quot;`/control/`&quot;">​</a></h3><p>This implies privileged mutation even on read-only status and ordinary product pages.</p><h3 id="dashboard" tabindex="-1"><code>/dashboard/</code> <a class="header-anchor" href="#dashboard" aria-label="Permalink to &quot;`/dashboard/`&quot;">​</a></h3><p>This describes one presentation rather than a durable platform interface.</p><h3 id="admin" tabindex="-1"><code>/admin/</code> <a class="header-anchor" href="#admin" aria-label="Permalink to &quot;`/admin/`&quot;">​</a></h3><p>This is overly generic, implies elevated authority, and remains reserved from the Pi-hole namespace.</p><h3 id="use-a-container-management-dashboard" tabindex="-1">Use a container-management dashboard <a class="header-anchor" href="#use-a-container-management-dashboard" aria-label="Permalink to &quot;Use a container-management dashboard&quot;">​</a></h3><p>Infrastructure objects are not the Sovereign product model and exposing them would broaden privileges and confuse service health with user outcomes.</p>',24)])])}const m=a(i,[["render",r]]);export{p as __pageData,m as default};
